// Input from previous node
const input = $input.item.json;

// Step 1: Get the keyword string
const keywordString = input.Keyword || "";

// Step 2: Split string into individual keywords
const keywordsArray = keywordString
  .split(/\s{2,}/)       // split by 2 or more spaces
  .map(k => k.trim())    // remove extra spaces
  .filter(k => k !== ''); // remove empty strings

// Step 3: Convert into n8n items format
return keywordsArray.map(k => ({
  json: { keyword: k }
}));

const webhookData = $input.item.json;

// Extract body data
const data = webhookData.body;

// Normalize data according to your sheet columns
const normalizedData = {
  // Your sheet columns in exact order:

  // 1. organizationIndustry
  organizationIndustry: data.organizationIndustry || "",

  // 2. email
  email: data.email || "",

  // 3. city
  city: data.city || "",

  // 4. state
  state: data.state || "",

  // 5. country
  country: data.country || "",

  // 6. organizationSize
  organizationSize: data.organizationSize || "",

  // 7. organizationLinkedinUrl
  organizationLinkedinUrl: data.organizationLinkedinUrl || "",

  // 8. organizationWebsiteUrl
  organizationWebsiteUrl: data.organizationWebsiteUrl || "",

  // 9. organizationFoundedYear
  organizationFoundedYear: data.organizationFoundedYear || "",

  // 10. organizationDescription
  organizationDescription: data.organizationDescription || "",

  // 11. emailContent
  emailContent: data.emailContent || "",

  // 12. Status (from webhook)
  Status: data.status || "",

  // Additional useful data for email sending:
  fullName: data.fullName || "",
  position: data.position || "",
  organizationName: data.organizationName || "",

  // Tracking
  sheetRow: data.sheetRow,
  eventId: data.eventId,
  timestamp: data.timestamp
};

// Log for debugging
console.log("Normalized Data:", JSON.stringify(normalizedData, null, 2));

return [{ json: normalizedData }];

// Get the input data safely
let emailContent = "";

try {
  // Method 1: Try to get data from common structures
  const inputData = $input.item.json;

  if (inputData.body && inputData.body.emailContent) {
    emailContent = inputData.body.emailContent;
  } else if (inputData.emailContent) {
    emailContent = inputData.emailContent;
  } else if (inputData[0] && inputData[0].json && inputData[0].json.body && inputData[0].json.body.emailContent) {
    emailContent = inputData[0].json.body.emailContent;
  } else {
    // Try to find email content in any format
    const jsonStr = JSON.stringify(inputData);
    const match = jsonStr.match(/"emailContent":"([^"]+)"/);
    if (match) {
      emailContent = match[1].replace(/\\n/g, '\n');
    }
  }
} catch (error) {
  console.log("Error getting data:", error);
  emailContent = "";
}

console.log("Email content length:", emailContent.length);

// Extract subject and body
let subject = "Automation Proposal";
let body = "";

if (emailContent && emailContent.trim() !== "") {
  // Find subject
  const subjectMatch = emailContent.match(/Subject:\s*(.+?)(?:\n\n|\r\n\r\n|$)/im);
  if (subjectMatch) {
    subject = subjectMatch[1].trim();
    // Remove subject line
    body = emailContent.replace(/Subject:\s*.+?(\n\n|\r\n\r\n|$)/im, '').trim();
  } else {
    body = emailContent.trim();
  }
}

console.log("Subject:", subject);
console.log("Body length:", body.length);

// Return the result
return [{
  json: {
    subject: subject,
    body: body
  }
}];

// Get all incoming items (n8n compatible)
const items = $input.all();

// Convert incoming JSON to string
const userInput = JSON.stringify(
  items.map(item => item.json)
);

// Return as output
return [
  {
    json: {
      userInput
    }
  }
];

